  showShopMenu.value = false
  await new Promise((resolve) => setTimeout(resolve, 300))
  await focusOnShopMarker(shopId)
  setTimeout(() => {
    selectedShopId.value = null
  }, 2000)
}

const openShopDetails = async (shopId: string) => {
  const shop = shops.value.find((s) => s.id === shopId)
  if (!shop) return
  showShopMenu.value = false
  await new Promise((resolve) => setTimeout(resolve, 300))
  router.push(`/shop/${shopId}`)
}

/* -------------------- ERROR MESSAGE HANDLER -------------------- */
let errorTimeout: number | null = null

const setErrorMessage = (message: string | null, duration: number = 4000) => {
  if (errorTimeout) {
    clearTimeout(errorTimeout)
    errorTimeout = null
  }

  errorMsg.value = null

  if (message) {
    setTimeout(() => {
      errorMsg.value = message

      if (duration > 0) {
        errorTimeout = window.setTimeout(() => {
          errorMsg.value = null
        }, duration)
      }
    }, 50)
  }
}

/* -------------------- LIFECYCLE -------------------- */
onMounted(async () => {
  console.log('Mounting map component...')

  try {
    await initializeMap()
    
    // Fetch shops first
    setTimeout(() => {
      doFetchShops(30)
    }, 100)

    // Load cached location immediately for map
    loadCachedLocation()
    
    // Handle location based on platform
    setTimeout(async () => {
      try {
        const platform = Capacitor.getPlatform()
        console.log('Platform detected:', platform)
        
        if (platform === 'android' || platform === 'ios') {
          // Use the composable for native platforms
          console.log('Using Capacitor Geolocation via composable')
          
          // Request permission and get location
          const hasPermission = await requestPermission()
          
          if (hasPermission) {
            try {
              const position = await getCurrentPosition()
              const lat = position.coords.latitude
              const lng = position.coords.longitude
              
              console.log('Location obtained:', { lat, lng })
              
              // Update map
              if (map.value) {
                createUserMarker(lat, lng)
                map.value.flyTo({
                  center: [lng, lat],
                  zoom: 15,
                  essential: true,
                  duration: 1000
                })
              }
              
              // Save to cache
              saveCachedLocation(lat, lng)
              
              // Start watching for updates
              await startWatching()
              
              setErrorMessage('📍 Location updated', 2000)
              
            } catch (error) {
              console.error('Failed to get location:', error)
              useFallbackLocation()
            }
          } else {
            console.warn('Location permission denied')
            setErrorMessage('📍 Location permission denied', 4000)
            useFallbackLocation()
          }
        } else {
          // Web platform
          console.log('Using web fallback')
          useFallbackLocation()
        }
      } catch (err) {
        console.error('Location error:', err)
        setErrorMessage('📍 Location access failed', 3000)
        useFallbackLocation()
      }
    }, 500)
    
  } catch (err) {
    console.warn('Map initialization error:', err)
    setErrorMessage('Map loading...', 2000)
    doFetchShops()
  }
})

// Keep this helper function
function useFallbackLocation() {
  if (lastKnown.value) {
    const [lat, lng] = lastKnown.value
    console.log('Using cached location:', { lat, lng })
    
    if (map.value) {
      createUserMarker(lat, lng)
      map.value.flyTo({
        center: [lng, lat],
        zoom: 13,
        essential: true,
        duration: 1000
      })
    }
    
    highlightUserCityBoundary(lat, lng)
    setErrorMessage('📍 Using last known location', 3000)
  } else {
    // Default to Manila
    const defaultLat = 14.5995
    const defaultLng = 120.9842
    
    console.log('Using default location:', { defaultLat, defaultLng })
    
    if (map.value) {
      createUserMarker(defaultLat, defaultLng)
      map.value.flyTo({
        center: [defaultLng, defaultLat],
        zoom: 12,
        essential: true,
        duration: 1000
      })
    }
    
    saveCachedLocation(defaultLat, defaultLng)
    highlightUserCityBoundary(defaultLat, defaultLng)
    setErrorMessage('📍 Using default location', 3000)
  }
}
// Android-specific location function
async function getAndroidLocation() {
  try {
    console.log('Getting Android device location...')
    
    const position = await Geolocation.getCurrentPosition({
      enableHighAccuracy: true,  // Use GPS for better accuracy
      timeout: 15000,            // 15 second timeout for Android
      maximumAge: 0             // Don't use cached position
    })
    
    const lat = position.coords.latitude
    const lng = position.coords.longitude
    
    console.log('Android location obtained:', { lat, lng, accuracy: position.coords.accuracy })
    
    // Update map with user location
    if (map.value) {
      createUserMarker(lat, lng)
      map.value.flyTo({
        center: [lng, lat],
        zoom: 15,
        essential: true,
        duration: 1000,
      })
    }
    
    // Save to cache
    saveCachedLocation(lat, lng)
    
    // Update reactive refs
    // Note: You need to update your composable's values
    // This might require a method to set latitude/longitude values
    
    setErrorMessage('Location updated successfully', 2000)
    
    // Start watching position for updates (optional)
    startAndroidLocationWatch()
    
  } catch (error) {
    console.error('Failed to get Android location:', error)
    
    // Handle specific Android error codes
    if (error instanceof Error) {
      const message = error.message.toLowerCase()
      
      if (message.includes('denied') || message.includes('permission')) {
        setErrorMessage('Location permission denied. Using last known location.', 4000)
      } else if (message.includes('unavailable') || message.includes('disabled')) {
        setErrorMessage('GPS is disabled. Please enable location.', 5000)
      } else if (message.includes('timeout')) {
        setErrorMessage('Location timed out. Using last known location.', 3000)
      } else {
        setErrorMessage('Unable to get location. Using last known location.', 3000)
      }
    }
    
    useCachedLocation()
  }
}

// Optional: Watch for location updates on Android
async function startAndroidLocationWatch() {
  try {
    console.log('Starting Android location watch...')
    
    await Geolocation.watchPosition(
      {
        enableHighAccuracy: true,
        timeout: 10000,
        maximumAge: 0
      },
      (position, err) => {
        if (err) {
          console.error('Location watch error:', err)
          return
        }
        
        if (position) {
          console.log('Location updated via watch:', position.coords)
          
          // Update user marker
          if (userMarker && map.value) {
            userMarker.setLngLat([position.coords.longitude, position.coords.latitude])
          }
          
          // Save updated location
          saveCachedLocation(position.coords.latitude, position.coords.longitude)
        }
      }
    )
  } catch (error) {
    console.warn('Could not start location watch:', error)
  }
}

function useCachedLocation() {
  if (lastKnown.value) {
    const [cachedLat, cachedLng] = lastKnown.value
    console.log('Using cached location:', { cachedLat, cachedLng })
    
    if (map.value) {
      createUserMarker(cachedLat, cachedLng)
      map.value.flyTo({
        center: [cachedLng, cachedLat],
        zoom: 13,
        essential: true,
        duration: 1000,
      })
    }
    
    // Also fetch shops with this location
    highlightUserCityBoundary(cachedLat, cachedLng)
    
  } else {
    // Default to Manila if no cached location
    const defaultLat = 14.5995
    const defaultLng = 120.9842
    console.log('Using default location:', { defaultLat, defaultLng })
    
    if (map.value) {
      createUserMarker(defaultLat, defaultLng)
      map.value.flyTo({
        center: [defaultLng, defaultLat],
        zoom: 12,
        essential: true,
        duration: 1000,
      })
    }
    
    saveCachedLocation(defaultLat, defaultLng)
    highlightUserCityBoundary(defaultLat, defaultLng)
  }
}

watch(
  [latitude, longitude],
  async ([lat, lng]) => {
    if (!map.value || lat == null || lng == null) return

    const userLat = Number(lat)
    const userLng = Number(lng)

    if (!isFinite(userLat) || !isFinite(userLng)) return

    const now = Date.now()
    if (now - lastUpdateTs < 1000) {
      saveCachedLocation(userLat, userLng)
      return
    }
    lastUpdateTs = now

    hasValidLocation.value = true

    if (userMarker) {
      userMarker.setLngLat([userLng, userLat])
    } else {
      createUserMarker(userLat, userLng)
    }

    saveCachedLocation(userLat, userLng)
    await highlightUserCityBoundary(userLat, userLng)
    void doFetchShops()
  },
  { immediate: true },
)

onUnmounted(() => {
  stopWatching()
  if (map.value) {
    try {
      map.value.remove()
    } catch (e) {
      console.warn('Error removing map:', e)
    }
  }
})
